// --- template mock.gotpl ---
func NewMock() (*PrismaClient, *Mock, func(t *testing.T)) {
	expectations := new([]mock.Expectation)
	pc := newMockClient(expectations)
	m := &Mock{
		Mock: &mock.Mock{
			Expectations: expectations,
		},
	}

	m.Usuario = usuarioMock{
		mock: m,
	}

	m.Roles = rolesMock{
		mock: m,
	}

	m.Permisos = permisosMock{
		mock: m,
	}

	m.RolePermisos = rolePermisosMock{
		mock: m,
	}

	m.UsuarioRoles = usuarioRolesMock{
		mock: m,
	}

	m.Evento = eventoMock{
		mock: m,
	}

	m.Inscripcion = inscripcionMock{
		mock: m,
	}

	m.InscripcionHistorial = inscripcionHistorialMock{
		mock: m,
	}

	m.NotificacionPreferencia = notificacionPreferenciaMock{
		mock: m,
	}

	m.Notificacion = notificacionMock{
		mock: m,
	}

	m.ReporteProgramado = reporteProgramadoMock{
		mock: m,
	}

	m.JobExecution = jobExecutionMock{
		mock: m,
	}

	m.Pais = paisMock{
		mock: m,
	}

	m.Ciudad = ciudadMock{
		mock: m,
	}

	m.Sesion = sesionMock{
		mock: m,
	}

	m.SesionPonente = sesionPonenteMock{
		mock: m,
	}

	return pc, m, m.Ensure
}

